%%%%%%%%%% Function fClcEngMapV01.m %%%%%%%%%%% Function Culclate Enge function Map, ver.1%% Kei Nakamura% Created on Friday, May 25th 2007.% Modified on%% function fld = fClcEngMapV01(r,eng,effRds,gap);% gives map of the value of enge function% fld: field map% r: map of radius% eng: eng coefficients% effRds: effective radius% gap: gap of the magnetfunction fld = fClcEngMapV01(r,eng,effRds,gap);fld2 = eng(2)*((r-effRds)/gap);                         % enge fit calculationfld3 = eng(3)*((r-effRds)/gap).^2;fld4 = eng(4)*((r-effRds)/gap).^3;fld5 = eng(5)*((r-effRds)/gap).^4;fld6 = eng(6)*((r-effRds)/gap).^5;fld1 = 1+exp(eng(1)+fld2+fld3+fld4+fld5+fld6);fld = 1./fld1;
